const express = require('express');
const axios = require('axios');
const { URL } = require('url');
const dns = require('dns').promises;

const app = express();

// Allowlist of permitted domains
const ALLOWED_DOMAINS = [
  'api.example.com',
  'cdn.example.com',
  'images.example.com'
];

// Blocked IP ranges (RFC 1918, loopback, metadata services)
const BLOCKED_IP_RANGES = [
  /^127\./, // Loopback
  /^10\./, // Private Class A
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./, // Private Class B
  /^192\.168\./, // Private Class C
  /^169\.254\./, // Link-local (AWS/Azure/GCP metadata)
  /^0\./, // Reserved
  /^224\./, // Multicast
  /^::1$/, // IPv6 loopback
  /^fc00:/, // IPv6 private
  /^fe80:/ // IPv6 link-local
];

function isBlockedIP(ip) {
  return BLOCKED_IP_RANGES.some(pattern => pattern.test(ip));
}

async function validateUrl(urlString) {
  let parsedUrl;

  try {
    parsedUrl = new URL(urlString);
  } catch (error) {
    throw new Error('Invalid URL format');
  }

  // Only allow HTTPS protocol
  if (parsedUrl.protocol !== 'https:') {
    throw new Error('Only HTTPS protocol is allowed');
  }

  // Validate against domain allowlist
  if (!ALLOWED_DOMAINS.includes(parsedUrl.hostname)) {
    throw new Error(`Domain ${parsedUrl.hostname} is not in allowlist`);
  }

  // Resolve DNS and check for blocked IPs (prevent DNS rebinding)
  try {
    const addresses = await dns.resolve4(parsedUrl.hostname);

    for (const ip of addresses) {
      if (isBlockedIP(ip)) {
        throw new Error(`Resolved IP ${ip} is in blocked range`);
      }
    }
  } catch (error) {
    if (error.code === 'ENOTFOUND') {
      throw new Error('Domain could not be resolved');
    }
    throw error;
  }

  return parsedUrl.href;
}

app.get('/api/fetch', async (req, res) => {
  const { url } = req.query;

  if (!url) {
    return res.status(400).json({ error: 'URL parameter is required' });
  }

  try {
    // Validate URL before making request
    const validatedUrl = await validateUrl(url);

    // Make HTTP request with timeout and size limits
    const response = await axios.get(validatedUrl, {
      timeout: 5000, // 5 second timeout
      maxContentLength: 10 * 1024 * 1024, // 10MB max
      maxRedirects: 0, // Disable redirects to prevent bypass
      validateStatus: (status) => status < 400
    });

    res.json({ data: response.data });
  } catch (error) {
    console.error('URL fetch error:', error.message);
    res.status(400).json({ error: 'Failed to fetch URL', details: error.message });
  }
});

app.listen(3000, () => console.log('Server running on port 3000'));

