const express = require('express');
const axios = require('axios');
const { URL } = require('url');
const dns = require('dns').promises;
const ipaddr = require('ipaddr.js');

const app = express();

// Allowlist configuration
const ALLOWED_DOMAINS = ['api.example.com', 'cdn.example.com'];
const ALLOWED_PROTOCOLS = ['https:'];

// Comprehensive IP blocking (RFC 1918, loopback, link-local, etc.)
function isPrivateOrReservedIP(ip) {
  try {
    const addr = ipaddr.process(ip);

    if (addr.kind() === 'ipv4') {
      // Check various private/reserved ranges
      return (
        addr.match(ipaddr.parseCIDR('0.0.0.0/8')) ||      // Current network
        addr.match(ipaddr.parseCIDR('10.0.0.0/8')) ||     // Private Class A
        addr.match(ipaddr.parseCIDR('127.0.0.0/8')) ||    // Loopback
        addr.match(ipaddr.parseCIDR('169.254.0.0/16')) || // Link-local (METADATA!)
        addr.match(ipaddr.parseCIDR('172.16.0.0/12')) ||  // Private Class B
        addr.match(ipaddr.parseCIDR('192.168.0.0/16')) || // Private Class C
        addr.match(ipaddr.parseCIDR('224.0.0.0/4')) ||    // Multicast
        addr.match(ipaddr.parseCIDR('240.0.0.0/4'))       // Reserved
      );
    } else if (addr.kind() === 'ipv6') {
      return (
        addr.match(ipaddr.parseCIDR('::1/128')) ||        // Loopback
        addr.match(ipaddr.parseCIDR('fc00::/7')) ||       // Unique local
        addr.match(ipaddr.parseCIDR('fe80::/10'))         // Link-local
      );
    }
  } catch (e) {
    return true; // Block on parse error
  }
  return false;
}

async function validateAndSanitizeUrl(urlString) {
  // Parse URL
  let parsedUrl;
  try {
    parsedUrl = new URL(urlString);
  } catch (error) {
    throw new Error('Invalid URL format');
  }

  // Protocol validation
  if (!ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
    throw new Error(`Protocol ${parsedUrl.protocol} not allowed. Only HTTPS permitted.`);
  }

  // Domain allowlist check
  if (!ALLOWED_DOMAINS.includes(parsedUrl.hostname)) {
    throw new Error(`Domain ${parsedUrl.hostname} is not in allowlist`);
  }

  // Check if hostname is IP address (block direct IP access)
  if (ipaddr.isValid(parsedUrl.hostname)) {
    throw new Error('Direct IP addresses are not allowed');
  }

  // DNS resolution and validation (prevent DNS rebinding)
  let resolvedIPs;
  try {
    resolvedIPs = await dns.resolve4(parsedUrl.hostname);
  } catch (error) {
    throw new Error(`Failed to resolve hostname: ${error.message}`);
  }

  // Check all resolved IPs
  for (const ip of resolvedIPs) {
    if (isPrivateOrReservedIP(ip)) {
      throw new Error(`Resolved IP ${ip} is in blocked range (private/reserved)`);
    }
  }

  return parsedUrl.href;
}

// SECURE: URL fetch with comprehensive validation
app.get('/api/fetch', async (req, res) => {
  const { url } = req.query;

  if (!url) {
    return res.status(400).json({ error: 'URL parameter required' });
  }

  try {
    const validatedUrl = await validateAndSanitizeUrl(url);

    const response = await axios.get(validatedUrl, {
      timeout: 5000,
      maxContentLength: 10 * 1024 * 1024, // 10MB max
      maxRedirects: 0, // Disable redirects
      validateStatus: (status) => status < 400,
      headers: {
        'User-Agent': 'MyApp/1.0'
      }
    });

    // Log successful fetch for audit
    console.log(`[AUDIT] Successful URL fetch: ${validatedUrl} by IP ${req.ip}`);

    res.json({ data: response.data });
  } catch (error) {
    // Log failed attempts for security monitoring
    console.warn(`[SECURITY] Blocked URL fetch attempt: ${url} by IP ${req.ip} - ${error.message}`);
    res.status(400).json({ error: 'Failed to fetch URL', details: error.message });
  }
});

// SECURE: Webhook with validation
app.post('/api/webhook', async (req, res) => {
  const { callbackUrl, event } = req.body;

  try {
    const validatedUrl = await validateAndSanitizeUrl(callbackUrl);

    await axios.post(validatedUrl, {
      event,
      timestamp: Date.now()
      // Never send sensitive internal data
    }, {
      timeout: 3000,
      maxRedirects: 0
    });

    res.json({ status: 'webhook sent' });
  } catch (error) {
    console.warn(`[SECURITY] Blocked webhook attempt: ${callbackUrl}`);
