package com.example.secure;

import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import inet.ipaddr.IPAddress;
import inet.ipaddr.IPAddressString;

import java.net.URI;
import java.net.InetAddress;
import java.net.UnknownHostException;
import java.util.Arrays;
import java.util.List;
import java.util.Set;

@RestController
@RequestMapping("/api")
public class SecureController {

    private final UrlValidationService urlValidationService;
    private final RestTemplate restTemplate;

    public SecureController(UrlValidationService urlValidationService) {
        this.urlValidationService = urlValidationService;
        this.restTemplate = new RestTemplate();
    }

    // SECURE: URL fetch with validation
    @GetMapping("/fetch")
    public ResponseEntity<?> fetchUrl(@RequestParam String url) {
        try {
            String validatedUrl = urlValidationService.validateAndSanitize(url);
            String response = restTemplate.getForObject(validatedUrl, String.class);
            return ResponseEntity.ok(response);
        } catch (SecurityException e) {
            return ResponseEntity.status(400).body(Map.of("error", e.getMessage()));
        }
    }
}

@Service
class UrlValidationService {

    private static final Set<String> ALLOWED_DOMAINS = Set.of(
        "api.example.com",
        "cdn.example.com"
    );

    private static final List<String> ALLOWED_PROTOCOLS = List.of("https");

    // Private IP ranges (CIDR notation)
    private static final List<String> BLOCKED_IP_RANGES = Arrays.asList(
        "0.0.0.0/8",        // Current network
        "10.0.0.0/8",       // Private Class A
        "127.0.0.0/8",      // Loopback
        "169.254.0.0/16",   // Link-local (AWS/Azure/GCP metadata)
        "172.16.0.0/12",    // Private Class B
        "192.168.0.0/16",   // Private Class C
        "224.0.0.0/4",      // Multicast
        "240.0.0.0/4",      // Reserved
        "::1/128",          // IPv6 loopback
        "fc00::/7",         // IPv6 unique local
        "fe80::/10"         // IPv6 link-local
    );

    public String validateAndSanitize(String urlString) throws SecurityException {
        URI uri;

        try {
            uri = new URI(urlString);
        } catch (Exception e) {
            throw new SecurityException("Invalid URL format");
        }

        // Protocol validation
        if (!ALLOWED_PROTOCOLS.contains(uri.getScheme())) {
            throw new SecurityException("Only HTTPS protocol is allowed");
        }

        // Domain allowlist
        String host = uri.getHost();
        if (!ALLOWED_DOMAINS.contains(host)) {
            throw new SecurityException("Domain not in allowlist: " + host);
        }

        // Check if host is IP address (block direct IP access)
        if (isIpAddress(host)) {
            throw new SecurityException("Direct IP addresses are not allowed");
        }

        // DNS resolution and IP validation
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);

            for (InetAddress addr : addresses) {
                String ip = addr.getHostAddress();

                if (isBlockedIP(ip)) {
                    throw new SecurityException(
                        "Resolved IP " + ip + " is in blocked range (private/reserved)"
                    );
                }
            }
        } catch (UnknownHostException e) {
            throw new SecurityException("Failed to resolve hostname: " + host);
        }

        return uri.toString();
    }

    private boolean isIpAddress(String host) {
        return new IPAddressString(host).isIPAddress();
    }

    private boolean isBlockedIP(String ipString) {
        IPAddressString ipAddrStr = new IPAddressString(ipString);

        if (!ipAddrStr.isIPAddress()) {
            return true; // Invalid IP = block
        }

        IPAddress ipAddr = ipAddrStr.getAddress();

        // Check against all blocked ranges
        for (String blockedRange : BLOCKED_IP_RANGES) {
            IPAddressString rangeStr = new IPAddressString(blockedRange);
            if (rangeStr.contains(ipAddr)) {
                return true;
            }
        }

        return false;
    }
}

